import React, { useCallback, useMemo, useState } from 'react';
import { LinErpListFilterBar, Select, dispatchAppToast } from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../../store/hooks';
import { analyticsService } from '../../../services/analytics/analyticsService';
import { formatVnd } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import reportStyles from '../../../styles/erpReportPage.module.css';
import type { ExpenseSummaryRow } from '../../../services/analytics/models';
import { AnalyticsReportShell, ReportTabBar, ReportTableWrap } from '../../../components/report';

const TEST_ID = 'erp-bao-cao-chi-phi';
const PAGE_ID = 'baocao-chi-phi';
const TABS = [
  { id: 'month', label: 'Tháng' },
  { id: 'quarter', label: 'Quý' },
  { id: 'year', label: 'Năm' },
];

const BaoCaoChiPhiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [tab, setTab] = useState('month');
  const [rows, setRows] = useState<ExpenseSummaryRow[]>([]);
  const [loading, setLoading] = useState(false);

  const handleLoad = useCallback(() => {
    setLoading(true);
    analyticsService
      .getExpenseSummary({ granularity: tab })
      .then(setRows)
      .catch(err =>
        dispatchAppToast(dispatch, {
          message: getApiErrorMessage(err, 'Lỗi'),
          type: 'error',
        }),
      )
      .finally(() => setLoading(false));
  }, [tab, dispatch]);

  const listFilters = useMemo(
    () => (
      <LinErpListFilterBar
        testIdPrefix={TEST_ID}
        onDateChange={() => {}}
        onSearch={handleLoad}
        searchAriaLabel="Xem"
        loading={loading}
        leading={(
          <div data-testid={`${TEST_ID}-field-granularity`}>
            <Select
              label="Kỳ"
              value={tab}
              onChange={e => setTab(e.target.value)}
              options={TABS.map(t => ({ value: t.id, label: t.label }))}
              size="small"
            />
          </div>
        )}
      />
    ),
    [tab, handleLoad, loading],
  );

  return (
    <AnalyticsReportShell
      testId={TEST_ID}
      pageId={PAGE_ID}
      title="Báo cáo chi phí"
      titleIconClass="fas fa-receipt"
      loading={loading}
      hasData={rows.length > 0}
      filters={listFilters}
      onLoad={handleLoad}
      exportPath="/accounting/reports/expense-summary/export-excel"
      exportParams={{ granularity: tab }}
      exportFilename={`ChiPhi-${tab}.xlsx`}
      tabBar={<ReportTabBar testId={TEST_ID} tabs={TABS} activeId={tab} onChange={setTab} />}
    >
      <ReportTableWrap testId={`${TEST_ID}-grid`}>
        <thead>
          <tr>
            <th>Kỳ</th>
            <th>Loại</th>
            <th className={reportStyles.colRight}>Chi phí</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, i) => (
            <tr key={i}>
              <td>{r.period}</td>
              <td>{r.category ?? '—'}</td>
              <td className={reportStyles.colRight}>{formatVnd(r.expense)}</td>
            </tr>
          ))}
        </tbody>
      </ReportTableWrap>
    </AnalyticsReportShell>
  );
};

export default BaoCaoChiPhiPage;
